5.query:
timeseries response_time = percentile(dt.service.request.response_time, 50, filter: { in(dt.entity.service, classicEntitySelector("type(service),servicetype(\"DATABASE_SERVICE\")")) }), by: { dt.entity.service }
| sort arrayPercentile(response_time, 50) desc
| limit 20

